using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

public sealed class WebSearchTool
{
    private readonly HttpClient _httpClient = new();

    [Description("Searches the web for a given query and returns a list of result titles, snippets, and URLs. Use this to find information about a topic.")]
    public async Task<string> SearchWeb(
        [Description("The search query string")] string query,
        [Description("Maximum number of results to return (1-10)")] int maxResults = 5)
    {
        maxResults = Math.Clamp(maxResults, 1, 10);

        try
        {
            // Use DuckDuckGo Instant Answer API (no key required)
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
            var response = await _httpClient.GetFromJsonAsync<JsonElement>(url);

            var results = new List<string>();

            // Extract abstract if available
            var abstractText = response.GetProperty("Abstract").GetString();
            var abstractUrl = response.GetProperty("AbstractURL").GetString();
            if (!string.IsNullOrWhiteSpace(abstractText))
            {
                results.Add($"[Summary] {abstractText}\nSource: {abstractUrl}");
            }

            // Extract related topics
            if (response.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var topic in topics.EnumerateArray().Take(maxResults))
                {
                    if (topic.TryGetProperty("Text", out var text) &&
                        topic.TryGetProperty("FirstURL", out var topicUrl))
                    {
                        results.Add($"- {text.GetString()}\n  URL: {topicUrl.GetString()}");
                    }
                }
            }

            if (results.Count == 0)
            {
                return $"No detailed results found for '{query}'. Try rephrasing or breaking the query into simpler terms.";
            }

            return $"Search results for '{query}':\n\n{string.Join("\n\n", results)}";
        }
        catch (Exception ex)
        {
            return $"Search failed for '{query}': {ex.Message}. Try a different query.";
        }
    }
}

using System.ComponentModel;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

public sealed class NoteTool
{
    private readonly List<NoteEntry> _notes = [];

    [Description("Saves a research note with a title and content. Use this to record key findings during research.")]
    public string SaveNote(
        [Description("A short title for the note")] string title,
        [Description("The note content — facts, insights, or quotes")] string content,
        [Description("The source URL or reference, if any")] string? source = null)
    {
        _notes.Add(new NoteEntry(title, content, source));
        return $"Note saved: '{title}' (total notes: {_notes.Count})";
    }

    [Description("Retrieves all saved research notes collected so far.")]
    public string GetAllNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes have been saved yet.";
        }

        var formatted = _notes.Select((n, i) =>
        {
            var src = string.IsNullOrWhiteSpace(n.Source) ? "" : $"\n   Source: {n.Source}";
            return $"{i + 1}. [{n.Title}]\n   {n.Content}{src}";
        });

        return $"Research notes ({_notes.Count} total):\n\n{string.Join("\n\n", formatted)}";
    }

    private sealed record NoteEntry(string Title, string Content, string? Source);
}

