using Microsoft.Extensions.AI;
using Microsoft.Agents.AI;
using ResearchAgent.Tools;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- Build the chat client ---
IChatClient chatClient = new OpenAI.OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Create tools ---
var webSearch = new WebSearchTool();
var notes = new NoteTool();

var tools = new AIFunctionFactory[] { }; // placeholder — we register via AIFunction below
List<AITool> agentTools =
[
    AIFunctionFactory.Create(webSearch.SearchWeb),
    AIFunctionFactory.Create(notes.SaveNote),
    AIFunctionFactory.Create(notes.GetAllNotes),
];

// --- Create the agent ---
var agent = new ChatClientAgent(chatClient, "ResearchAgent")
{
    Instructions = """
        You are a research agent. Your goal is to thoroughly research a user-provided topic by:
        1. Searching the web for relevant information using multiple queries.
        2. Saving key findings as notes (include sources).
        3. After gathering enough information, retrieve all notes and produce a well-structured summary.

        Strategy:
        - Start with a broad search, then drill into specific subtopics.
        - Save a note for each important finding before moving on.
        - Aim for at least 3-5 notes before summarizing.
        - End with a clear, cited summary of your research.
        """,
    Tools = agentTools,
};

// --- Get topic from user ---
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n{"".PadRight(50, '-')}");

// --- Run the agent ---
var history = new List<ChatMessage>
{
    new(ChatRole.User, $"Research this topic and provide a comprehensive summary: {topic}"),
};

var options = new AgentInvokeOptions
{
    MaximumIterations = 10,
};

string? finalResponse = null;

await foreach (var message in agent.InvokeStreamingAsync(history, options))
{
    if (message.Role == ChatRole.Assistant && !string.IsNullOrWhiteSpace(message.Text))
    {
        Console.Write(message.Text);
        finalResponse = message.Text;
    }
}

Console.WriteLine($"\n{"".PadRight(50, '-')}\nResearch complete.");

